/**
 * Represents a Llama.
*/
export class Llama extends ChestedHorse {
  /**
   * Gets the llama's color.
   *
   * @return a {@link Color} representing the llama's color
  */
  get color(): org_bukkit_entity_Llama_Color;
  /**
   * Sets the llama's color.
   *
   * @param color a {@link Color} for this llama
  */
  set color(color: org_bukkit_entity_Llama_Color);
  /**
   * Gets the llama's strength. A higher strength llama will have more
   * inventory slots and be more threatening to entities.
   *
   * @return llama strength [1,5]
  */
  get strength(): number;
  /**
   * Sets the llama's strength. A higher strength llama will have more
   * inventory slots and be more threatening to entities. Inventory slots are
   * equal to strength * 3.
   *
   * @param strength llama strength [1,5]
  */
  set strength(strength: number);
  get inventory(): LlamaInventory;
  /**
   * Checks if this llama is in a caravan.
   * This means that this llama is currently following
   * another llama.
   *
   * @return is in caravan
  */
  inCaravan(): boolean;
  /**
   * Joins a caravan, with the provided llama being the leader
   * of the caravan.
   * This llama will then follow the provided llama.
   *
   * @param llama head of caravan to join
  */
  joinCaravan(llama: Llama): void;
  /**
   * Leaves the current caravan that they are in.
  */
  leaveCaravan(): void;
  /**
   * Get the llama that this llama is following.
   * 
   * Does not necessarily mean the leader of the entire caravan.
   *
   * @return the llama currently being followed
  */
  get caravanHead(): Llama | null;
  /**
   * Checks if another llama is currently following behind
   * this llama.
   *
   * @return true if being followed in the caravan
  */
  hasCaravanTail(): boolean;
  /**
   * Gets the llama that is currently following behind
   * this llama.
   *
   * @return the llama following this llama, or null if none is following them
  */
  get caravanTail(): Llama | null;
}
export interface Llama extends ChestedHorse, RangedEntity {}
/**
 * Represents a mushroom {@link Cow}
*/
export class MushroomCow extends AbstractCow {
  /**
   * Checks for the presence of custom potion effects to be applied to the
   * next suspicious stew received from milking this {@link MushroomCow}.
   *
   * @return true if custom potion effects are applied to the stew
  */
  hasEffectsForNextStew(): boolean;
  /**
   * Gets an immutable list containing all custom potion effects applied to
   * the next suspicious stew received from milking this {@link MushroomCow}.
   * 
   * Plugins should check that hasCustomEffects() returns true before calling
   * this method.
   *
   * @return an immutable list of custom potion effects
  */
  get effectsForNextStew(): PotionEffect[];
  /**
   * Adds a custom potion effect to be applied to the next suspicious stew
   * received from milking this {@link MushroomCow}.
   *
   * @deprecated use {@link #addEffectToNextStew(io.papermc.paper.potion.SuspiciousEffectEntry, boolean)} as PotionEffect suggests that all attributes are used. In fact, only the PotionEffectType and the duration are used.
   * @param effect the potion effect to add
   * @param overwrite true if any existing effect of the same type should be
   * overwritten
   * @return true if the effects to be applied to the suspicious stew changed
   * as a result of this call
  */
  addEffectToNextStew(effect: PotionEffect, overwrite: boolean): boolean;
  /**
   * Adds a suspicious effect entry to be applied to the next suspicious stew
   * received from milking this {@link MushroomCow}.
   *
   * @param suspiciousEffectEntry the suspicious effect entry to add
   * @param overwrite true if any existing effect of the same type should be
   * overwritten
   * @return true if the effects to be applied to the suspicious stew changed
   * as a result of this call
  */
  addEffectToNextStew(suspiciousEffectEntry: SuspiciousEffectEntry, overwrite: boolean): boolean;
  /**
   * Removes a custom potion effect from being applied to the next suspicious
   * stew received from milking this {@link MushroomCow}.
   *
   * @param type the potion effect type to remove
   * @return true if the effects to be applied to the suspicious stew changed
   * as a result of this call
  */
  removeEffectFromNextStew(type: PotionEffectType): boolean;
  /**
   * Checks for a specific custom potion effect type to be applied to the next
   * suspicious stew received from milking this {@link MushroomCow}.
   *
   * @param type the potion effect type to check for
   * @return true if the suspicious stew to be generated has this effect
  */
  hasEffectForNextStew(type: PotionEffectType): boolean;
  /**
   * Removes all custom potion effects to be applied to the next suspicious
   * stew received from milking this {@link MushroomCow}.
  */
  clearEffectsForNextStew(): void;
  /**
   * Get the variant of this cow.
   *
   * @return cow variant
  */
  get variant(): org_bukkit_entity_MushroomCow_Variant;
  /**
   * Set the variant of this cow.
   *
   * @param variant cow variant
  */
  set variant(variant: org_bukkit_entity_MushroomCow_Variant);
  /**
   * Gets how long the effect applied to stew
   * from this mushroom cow is.
   *
   * @return duration of the effect (in ticks)
   * @deprecated Mushroom cows can now hold multiple effects, use {@link #getStewEffects()}
  */
  get stewEffectDuration(): number;
  /**
   * Sets how long the effect applied to stew
   * from this mushroom cow is.
   *
   * @param duration duration of the effect (in ticks)
   * @deprecated Mushroom cows can now hold multiple effects, use {@link #setStewEffects(java.util.List)}
  */
  set stewEffectDuration(stewEffectDuration: number);
  /**
   * Gets the type of effect applied to stew
   * from this mushroom cow is.
   *
   * @return effect type, or null if an effect is currently not set
   * @deprecated Mushroom cows can now hold multiple effects, use {@link #getStewEffects()}
   * @throws UnsupportedOperationException
  */
  get stewEffectType(): PotionEffectType;
  /**
   * Sets the type of effect applied to stew
   * from this mushroom cow is.
   *
   * @param type new effect type
   *             or null if this cow does not give effects
   * @deprecated Mushroom cows can now hold multiple effects, use {@link #setStewEffects(java.util.List)}
   * @throws UnsupportedOperationException
  */
  set stewEffect(stewEffect: PotionEffectType | null);
  /**
   * Returns an immutable collection of the effects applied to stew
   * items for this mushroom cow.
   *
   * @return immutable effect entry collection
  */
  get stewEffects(): SuspiciousEffectEntry[];
  /**
   * Sets effects applied to stew items for this mushroom cow.
   *
   * @param effects effect entry list
  */
  set stewEffects(stewEffects: SuspiciousEffectEntry[]);
}
export interface MushroomCow extends AbstractCow, Shearable {}
